171â†’internal class RangeTree(seq: List<Int> = emptyList()) {
172â†’    private var emptyArrayView = ArrayView(0, 0)
173â†’    private var arr: IntArray = seq.toIntArray()
174â†’
175â†’    init {
176â†’        if (arr.isNotEmpty()) {
177â†’            arr.reduce { p, n -> require(p <= n) { "Input must be sorted" }; n }
178â†’        }
179â†’    }
180â†’
181â†’    // runtime: O(log(n)+k), where k is number of matching points
182â†’    // space: O(1)
183â†’    fun query(
184â†’        vmin: Int,
185â†’        vmax: Int,
186â†’    ): ArrayView {
187â†’        var r = arr.size - 1
188â†’        if (r == -1 || vmax < arr[0] || arr[r] < vmin) {
189â†’            return emptyArrayView
190â†’        }
191â†’        // binary search for min(arr[l] >= vmin)
192â†’        var l = 0
193â†’        while (l < r) {
194â†’            val m = (r + l) / 2
195â†’            if (vmax < arr[m]) {
196â†’                r = m - 1
197â†’            } else if (arr[m] < vmin) {
198â†’                l = m + 1
199â†’            } else {
200â†’                // arr[l] ?<=? vmin <= arr[m] <= vmax ?<=? arr[r]
201â†’                if (vmin <= arr[l]) break else l++ // optimization
202â†’                r = m
203â†’            }
204â†’        }
205â†’        if (l > r || arr[l] < vmin) {
206â†’            return emptyArrayView
207â†’        }
208â†’        // find max(k) such as arr[k] < vmax
209â†’        var k = l
210â†’        while (k < arr.size) {
211â†’            if (arr[k] >= vmax) {
212â†’                break
213â†’            }
214â†’            k++
215â†’        }
216â†’        return ArrayView(l, k)
217â†’    }
218â†’
219â†’    fun isEmpty(): Boolean = arr.isEmpty()
220â†’
221â†’    inner class ArrayView(private var l: Int, private val r: Int) {
222â†’        val size: Int = r - l
223â†’
224â†’        fun get(i: Int): Int {
225â†’            if (i < 0 || i >= size) {
226â†’                throw IndexOutOfBoundsException()
227â†’            }
228â†’            return arr[l + i]
229â†’        }
230â†’
231â†’        inline fun forEach(cb: (v: Int) -> Unit) {
232â†’            var i = 0
233â†’            while (i < size) {
234â†’                cb(get(i++))
235â†’            }
236â†’        }
237â†’
238â†’        override fun toString(): String {
239â†’            if (l == r) {
240â†’                return "[]"
241â†’            }
242â†’            val sb = StringBuilder("[")
243â†’            var i = l
244â†’            while (i < r) {
245â†’                sb.append(arr[i]).append(", ")
246â†’                i++
247â†’            }
248â†’            sb.replace(sb.length - 2, sb.length, "")
249â†’            sb.append("]")
250â†’            return sb.toString()
251â†’        }
252â†’    }
253â†’}
